import type { ComponentProps } from 'react';
import { TextareaControl } from '@wordpress/components';
import { __, _x } from '@wordpress/i18n';

interface AdditionalPromptControlProps extends ComponentProps<
  typeof TextareaControl
> {}

const DEFAULT_LABEL = __(
  'Custom prompt (optional)',
  'alt-text-generator-gpt-vision',
);

const DEFAULT_HELP = __(
  'Add instructions for the AI, such as keywords to include or style guidelines.',
  'alt-text-generator-gpt-vision',
);

const DEFAULT_PLACEHOLDER = _x(
  'e.g. Include terms like "AI" and "robotics"',
  'Additional prompt placeholder',
  'alt-text-generator-gpt-vision',
);

export default function CustomPromptControl({
  rows = 1,
  label = DEFAULT_LABEL,
  help = DEFAULT_HELP,
  placeholder = DEFAULT_PLACEHOLDER,
  ...props
}: AdditionalPromptControlProps) {
  return (
    <TextareaControl
      rows={rows}
      label={label}
      help={help}
      placeholder={placeholder}
      style={{
        // @ts-ignore - missing types for fieldSizing
        fieldSizing: 'content',
        maxBlockSize: '6rlh',
      }}
      {...props}
    />
  );
}
